//! Macro-benchmarks for realistic corpus processing
//!
//! These benchmarks operate on the MDN content corpus fetched by
//! `benches/fetch_corpora.sh`. The MDN repo (`mdn/content`) contains ~14 000
//! markdown files totalling ~55 MB of prose — large enough to trigger noet's
//! sharding strategy and reveal scaling behaviour invisible in the small
//! `tests/network_1` corpus.
//!
//! The MDN source tree almost has the layout noet expects:
//!
//! ```text
//! files/en-us/
//!   index.md                        ← generated by fetch_corpora.sh
//!   web/
//!     index.md                      ← subnet (present in repo)
//!     api/
//!       index.md                    ← subnet (present in repo)
//!       fetch_api/
//!         index.md
//!         ...
//!     ...
//!   ...
//! ```
//!
//! Every subdirectory already contains an `index.md`, but the root
//! `files/en-us/` directory does not. `fetch_corpora.sh` generates a minimal
//! `index.md` there after cloning so `NetworkCodec` treats it as the network
//! root. No other staging or copying is required.
//!
//! # Selecting a sub-corpus for fast development runs
//!
//! By default the benchmarks run over the full `files/en-us/` tree (~14 000
//! files). For faster iteration — smoke-testing correctness, profiling a
//! specific subsystem, or running in debug mode — set `NOET_BENCH_CORPUS` to a
//! path **relative to `files/en-us/`**:
//!
//! ```sh
//! # ~1 300 files, 14 MB — crosses the 10 MB shard threshold on its own
//! NOET_BENCH_CORPUS=web/javascript \
//!   cargo bench --bench macro_benchmarks --features bin,service
//!
//! # ~1 200 files
//! NOET_BENCH_CORPUS=web/css \
//!   cargo bench --bench macro_benchmarks --features bin,service
//!
//! # full corpus (default)
//! cargo bench --bench macro_benchmarks --features bin,service
//! ```
//!
//! The subdirectory must already have an `index.md` (all MDN subdirectories
//! do), so no extra setup is required.
//!
//! # Usage
//!
//! ```sh
//! # Fetch corpus first (sparse checkout, only *.md — takes ~30 s first time)
//! bash benches/fetch_corpora.sh
//!
//! # Run all macro-benchmarks
//! cargo bench --bench macro_benchmarks --features bin,service
//!
//! # Browse generated HTML output
//! open target/bench-output/mdn/index.html
//!
//! # Save a named baseline
//! cargo bench --bench macro_benchmarks --features bin,service -- --save-baseline main
//!
//! # Compare against a saved baseline
//! cargo bench --bench macro_benchmarks --features bin,service -- --baseline main
//! ```
//!
//! # Features required
//!
//! `--features bin,service` is required. `bin` triggers `build.rs` to compile
//! and embed the WASM viewer; `service` is required for `DocumentCompiler`.
//!
//! # Corpus absence
//!
//! If `.bench_corpora/mdn-content/` is missing (e.g. in CI jobs that skip the
//! fetch step), each benchmark prints a notice and returns immediately. The
//! bench binary still compiles and runs — it just records no measurements.

use criterion::{criterion_group, criterion_main, Criterion, Throughput};
use noet_core::{beliefbase::BeliefBase, codec::DocumentCompiler, event::BeliefEvent};
use std::path::{Path, PathBuf};
use tokio::sync::mpsc::unbounded_channel;

// ---------------------------------------------------------------------------
// Directory helpers
// ---------------------------------------------------------------------------

/// Root of the pristine fetched corpora, relative to the crate manifest.
fn corpora_root() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join(".bench_corpora")
}

/// The corpus root handed to `DocumentCompiler`.
///
/// Defaults to the full `files/en-us/` subtree. Override with
/// `NOET_BENCH_CORPUS=<relative-path>` to select a subdirectory for faster
/// development runs, e.g. `NOET_BENCH_CORPUS=web/javascript`.
fn mdn_corpus_src() -> PathBuf {
    let base = corpora_root()
        .join("mdn-content")
        .join("files")
        .join("en-us");

    match std::env::var("NOET_BENCH_CORPUS") {
        Ok(rel) if !rel.is_empty() && rel != "full" => {
            let sub = base.join(&rel);
            eprintln!(
                "  [macro_benchmarks] NOET_BENCH_CORPUS={rel} — using sub-corpus at {}",
                sub.display()
            );
            sub
        }
        _ => base,
    }
}

/// Stable HTML output directory for the MDN benchmark run.
///
/// Mirrors `mdn_corpus_src()`: if `NOET_BENCH_CORPUS` is set the output goes
/// into a subdirectory so full and partial runs don't overwrite each other.
fn mdn_html_output_dir() -> PathBuf {
    let base = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("target")
        .join("bench-output")
        .join("mdn");

    match std::env::var("NOET_BENCH_CORPUS") {
        Ok(rel) if !rel.is_empty() && rel != "full" => {
            // Replace path separators so "web/javascript" → "web-javascript"
            // (avoids creating nested output directories).
            base.join(rel.replace('/', "-"))
        }
        _ => base,
    }
}

// ---------------------------------------------------------------------------
// Corpus presence check
// ---------------------------------------------------------------------------

/// Return `Some(src_path)` if the selected corpus root is present and has a
/// root `index.md`, `None` otherwise (with a diagnostic on stderr).
fn require_mdn_corpus() -> Option<PathBuf> {
    let src = mdn_corpus_src();

    if !src.is_dir() {
        // Distinguish "corpus never fetched" from "bad NOET_BENCH_CORPUS value".
        let base = corpora_root()
            .join("mdn-content")
            .join("files")
            .join("en-us");
        if !base.is_dir() {
            eprintln!(
                "  [macro_benchmarks] MDN corpus not found at {} — \
                 run `bash benches/fetch_corpora.sh` to download. Skipping.",
                base.display()
            );
        } else {
            eprintln!(
                "  [macro_benchmarks] NOET_BENCH_CORPUS sub-path does not exist: {} \
                 — check your NOET_BENCH_CORPUS value. Skipping.",
                src.display()
            );
        }
        return None;
    }

    // Sanity-check: expect an index.md at the corpus root.
    if !src.join("index.md").exists() {
        eprintln!(
            "  [macro_benchmarks] corpus root at {} is missing index.md — \
             for the full corpus re-run `bash benches/fetch_corpora.sh --force`; \
             for a sub-corpus the subdirectory must already contain an index.md.",
            src.display()
        );
        return None;
    }

    let total = count_md_files(&src);
    let mb = total_md_bytes(&src) as f64 / 1024.0 / 1024.0;
    eprintln!(
        "  [macro_benchmarks] corpus ready: {} .md files, {:.1} MB at {}",
        total,
        mb,
        src.display()
    );

    Some(src)
}

// ---------------------------------------------------------------------------
// Corpus measurement helpers
// ---------------------------------------------------------------------------

/// Count `.md` files under a directory tree.
fn count_md_files(root: &Path) -> usize {
    walkdir::WalkDir::new(root)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.path().extension().map(|ext| ext == "md").unwrap_or(false))
        .count()
}

/// Approximate total byte size of all `.md` files under a directory tree.
fn total_md_bytes(root: &Path) -> u64 {
    walkdir::WalkDir::new(root)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.path().extension().map(|ext| ext == "md").unwrap_or(false))
        .filter_map(|e| e.metadata().ok())
        .map(|m| m.len())
        .sum()
}

// ---------------------------------------------------------------------------
// Core compilation helpers
// ---------------------------------------------------------------------------

/// Full parse + HTML generation for `corpus_root`, writing output to `html_out`.
/// Returns the number of compiled nodes.
///
/// This mirrors the `noet parse --html-output` command path, so the benchmark
/// exercises exactly what users get.
///
/// The `NOET_BASE_URL` environment variable is forwarded to the compiler when
/// set:
///
/// ```sh
/// NOET_BASE_URL=https://buildonomy.github.io/noet-core/corpus/mdn \
///   cargo bench --bench macro_benchmarks --features bin,service
/// ```
async fn run_parse_with_html(corpus_root: &Path, html_out: &Path) -> usize {
    std::fs::create_dir_all(html_out).expect("could not create HTML output dir");

    let base_url = std::env::var("NOET_BASE_URL").ok();

    let (tx, rx) = unbounded_channel::<BeliefEvent>();

    let processor = tokio::spawn(async move {
        let mut bb = BeliefBase::empty();
        let mut rx = rx;
        while let Some(event) = rx.recv().await {
            let _ = bb.process_event(&event);
        }
        bb
    });

    let mut compiler = DocumentCompiler::with_html_output(
        corpus_root,
        Some(tx),
        None,  // default max_reparse_count
        false, // write=false: do not modify source files
        Some(html_out.to_path_buf()),
        None,  // no live-reload script
        false, // no CDN
        base_url,
    )
    .expect("DocumentCompiler::with_html_output failed");

    let cache = compiler.builder().doc_bb().clone();
    compiler
        .parse_all(cache, false)
        .await
        .expect("parse_all failed");

    let node_count = compiler.cache().states().len();

    compiler.builder_mut().close_tx();
    let final_bb = processor.await.expect("event processor panicked");

    compiler
        .finalize_html(&final_bb)
        .await
        .expect("finalize_html failed");

    node_count
}

/// Run a single warm parse+HTML pass against a corpus that has already been
/// compiled once (BIDs written to disk). Returns the node count.
///
/// This is the setup-separated half of `bench_cache_warmup`: the cold pass
/// happens in the `setup` closure (outside the timed loop); only this warm
/// pass is measured.
async fn run_warm_parse_with_html(corpus_root: &Path, html_out: &Path) -> usize {
    run_parse_with_html(corpus_root, html_out).await
}

// ---------------------------------------------------------------------------
// Benchmark: single-pass parse + HTML throughput
// ---------------------------------------------------------------------------

fn bench_parse_throughput(c: &mut Criterion) {
    let Some(corpus) = require_mdn_corpus() else {
        eprintln!("  [macro_benchmarks] skipping parse_throughput");
        return;
    };

    let bytes = total_md_bytes(&corpus);
    let out_dir = mdn_html_output_dir();

    eprintln!(
        "  [macro_benchmarks] parse_throughput — {:.1} MB → HTML at {}",
        bytes as f64 / 1024.0 / 1024.0,
        out_dir.display(),
    );

    let rt = tokio::runtime::Runtime::new().unwrap();
    let mut group = c.benchmark_group("parse_throughput");
    group.throughput(Throughput::Bytes(bytes));

    group.bench_function("mdn_en_us", |b| {
        b.to_async(&rt)
            .iter(|| run_parse_with_html(&corpus, &out_dir));
    });

    group.finish();
}

// ---------------------------------------------------------------------------
// Benchmark: warm-cache speedup (isolated warm pass only)
//
// Strategy: use `iter_batched` so the cold pass runs in the `setup` closure
// (untimed), and only the warm pass — where BIDs are already written to disk —
// is measured. This gives a direct, apples-to-apples comparison against
// `bench_parse_throughput` (cold pass) without requiring manual subtraction.
// ---------------------------------------------------------------------------

fn bench_cache_warmup(c: &mut Criterion) {
    let Some(corpus) = require_mdn_corpus() else {
        eprintln!("  [macro_benchmarks] skipping cache_warmup");
        return;
    };

    let bytes = total_md_bytes(&corpus);
    let out_dir = mdn_html_output_dir();

    eprintln!(
        "  [macro_benchmarks] cache_warmup — cold pass (setup, untimed) then warm pass (timed)",
    );

    let rt = tokio::runtime::Runtime::new().unwrap();
    let mut group = c.benchmark_group("cache_warmup");
    group.throughput(Throughput::Bytes(bytes));

    // `iter_batched` runs `setup` before each timed `routine` invocation.
    // `setup` performs the cold parse (writes BIDs to disk); `routine` runs
    // the warm parse (reads existing BIDs). Only the warm pass is timed.
    //
    // BatchSize::PerIteration is correct here: each iteration needs a fresh
    // cold pass to guarantee the warm pass sees a fully written BID set.
    group.bench_function("mdn_en_us", |b| {
        b.iter_batched(
            // setup: cold parse — runs outside the timed region
            || {
                rt.block_on(run_parse_with_html(&corpus, &out_dir));
            },
            // routine: warm parse — this is what criterion times
            |()| rt.block_on(run_warm_parse_with_html(&corpus, &out_dir)),
            criterion::BatchSize::PerIteration,
        );
    });

    group.finish();
}

// ---------------------------------------------------------------------------
// Benchmark: graph query performance on a pre-compiled corpus
// ---------------------------------------------------------------------------
//
// Pre-compiles once outside the timed loop, then measures only graph traversal
// cost. HTML output from the pre-compile is left in place.

fn bench_graph_queries(c: &mut Criterion) {
    let Some(corpus) = require_mdn_corpus() else {
        eprintln!("  [macro_benchmarks] skipping graph_queries");
        return;
    };

    let out_dir = mdn_html_output_dir();

    let rt = tokio::runtime::Runtime::new().unwrap();

    let compiler = rt.block_on(async {
        run_parse_with_html(&corpus, &out_dir).await;

        let mut c =
            DocumentCompiler::simple(corpus.clone()).expect("DocumentCompiler::simple failed");
        c.parse_all(BeliefBase::default(), false)
            .await
            .expect("pre-compile failed");
        c
    });

    let node_count = compiler.cache().states().len();
    eprintln!(
        "  [macro_benchmarks] graph_queries — {} compiled nodes (HTML at {})",
        node_count,
        out_dir.display(),
    );

    let mut group = c.benchmark_group("graph_queries");
    group.throughput(Throughput::Elements(node_count as u64));

    group.bench_function("traverse_all_edges", |b| {
        b.iter(|| {
            let doc_count = compiler
                .cache()
                .states()
                .values()
                .filter(|node| node.kind.is_document())
                .count();

            let mut edge_count = 0usize;
            for node in compiler.cache().states().values() {
                if let Some(idx) = compiler.cache().bid_to_index(&node.bid) {
                    edge_count += compiler.cache().relations().as_graph().edges(idx).count();
                }
            }

            (doc_count, edge_count)
        });
    });

    group.finish();
}

// ---------------------------------------------------------------------------
// Criterion configuration and entry point
// ---------------------------------------------------------------------------

criterion_group! {
    name = macro_benches;
    config = Criterion::default()
        // Low sample count: each iteration involves real file I/O across
        // thousands of files. 10 samples still gives a statistically
        // meaningful result at this corpus scale.
        .sample_size(10)
        .measurement_time(std::time::Duration::from_secs(120));
    targets =
        bench_parse_throughput,
        bench_cache_warmup,
        bench_graph_queries
}

criterion_main!(macro_benches);
